 	 */
@@ -384,7 +389,7 @@ child_process(e, u)
 	 * we would block here.  thus we must fork again.
 	 */

-	if (*input_data && fork() == 0) {
+	if (*input_data && (stdinjob = fork()) == 0) {
 		register FILE	*out = fdopen(stdin_pipe[WRITE_PIPE], "w");
