+				if (!(mail = cron_popen(mailcmd, "w", e, &mailpid))) {
 					warn("%s", MAILCMD);
 					(void) _exit(ERROR_EXIT);
 				}
@@ -538,28 +537,54 @@ child_process(e, u)
 				if (mailto)
 					putc(ch, mail);
 			}
+		} /*if data from grandchild*/

-			/* only close pipe if we opened it -- i.e., we're
