-			 */
+		Debug(DPROC, ("[%d] got EOF from grandchild\n", getpid()))

-			if (mailto) {
-				Debug(DPROC, ("[%d] closing pipe to mail\n",
-					getpid()))
-				/* Note: the pclose will probably see
